INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05250', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '決策可說是管理活動的核心，無論是規劃、領導、控制等等活動都離不開決策，然而在決策 過程，決策者常會受到框架效應（framing effect）的影響而導致決策偏誤的現象。若決策者 在進行決策過程中時時督促自己多多涉獵各種相關案例，且會徵詢不同經驗者的意見，提醒 自己不輕易做出決定或判斷，此作法可以避免何種決策偏誤的出現？', '["代表偏誤", "定錨偏誤", "後見偏差", "應證偏誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05251', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某縣市政府之家庭暴力暨性侵害防治中心的組織劃分，是在中心主任下設置通報與轉介組、 個案管理組、宣導組與心理諮商組。這樣的組織劃分較符合那種向度區分？', '["依「方案」分", "依「功能」分", "依「產品／服務」分", "依「顧客／案主」分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05252', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Bradshaw 所提的四個需求是方案規劃進行需求評估時常被引用的觀點，下列描述何者屬於 「感受性需求」（felt need）？', '["對於經濟補助申請以政府所制定的貧窮線作為核定標準", "在學校針對全體學生進行調查，統計出自認情緒狀況不佳的人數，作為輔導方案規劃的基礎", "與乙社區比較之後，甲社區決議申請社區關懷據點，以服務社區中的長者", "某家庭福利服務中心統計過去一年的服務項目與服務人次，以為來年服務方案的規劃基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05253', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '邏輯模式提供一個檢驗和界定方案構成要素之架構，邏輯模式的要項有：輸入、過程、輸出、 成果、效應。下列敘述何者錯誤？', '["輸入（inputs）包含五項次要素：服務對象、工作人員、物質資源、設施、器材設備", "運作過程（throughputs）資料構成要素有：服務的定義、服務工作項目、處置方法", "輸出（outputs）是方案活動的直接產物，服務對象接受的服務量，構成要素有中間輸出、 最終輸出、品質滿意度", "成果（outcomes）的測量可透過數量的統計、標準化工具的測量、功能層次量表的施測、 測量服務對象的滿意程度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05254', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社會工作管理的活動中，規劃是引領社福機構經營與管理的藍圖，以為實務工作行動策略 的方針。然在規劃過程將面臨各種可能的阻力或障礙，需縝密考量並設法因應。「若管理者 在規劃過程中能將各個階段對未來可能產生的影響，以及未來情勢對組織目標的影響納入考 量，並讓規劃保持彈性」，如此作為可因應那一種規劃障礙？', '["規劃能力不足", "資訊使用不當", "重視局部而忽略整體", "僅重視可控制的變項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05255', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有效的服務方案設計應進行假設的陳述，勾勒出方案要做的事及方案要達成的目的，下列何 者不是方案假設的優點？', '["方案假設的形式就是針對某個特定的問題或情境，會以某種特定的處置方式因應", "方案假設可做為後續監督與評估服務提供過程的參考架構", "方案假設有助於將方案聚焦於工作人員所從事的各項活動，而非方案的問題", "方案假設可作為分析成本效益之資料庫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05256', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '福利混合經濟（The mixed economy of welfare）已是當前社會服務領域常見的服務輸送模式， 隨著社會、經濟與政治環境的變化，治理模式也逐漸轉變為網絡模式，其中各個部門之間是 否能建立起夥伴關係（partnership）將直接關係著網絡治理的成敗。下列對於夥伴關係的說 明，何者錯誤？', '["夥伴關係並非僅是網絡間的資源交換，更需要部門或機構間的協力與共識", "夥伴關係並非單一的概念，而是一種包含不同概念所構成的連續體", "夥伴關係在網絡之間的運作可以產生正向的結果，實務而言，其所帶來的正向影響之一即 是網絡間的運作成本降低，且自主與創新性可以提高", "夥伴關係自興起後被實踐至今，不少證據顯示其易流為空泛的言詞或口號，網絡間各個組 織的承諾易不足"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05257', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「針對正在執行中的方案，評估的重點是方案的發展、進行的步驟和方法，常藉由監測或回 饋等機制來了解方案如何進行、如何發揮效力、如何化解阻力、如何得到助力、為何成功、 為何失敗等等問題。」此描述主要為下列何種方案評估類型？', '["總結性評估", "可行性評估", "影響性評估", "形成性評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05258', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '進行社會工作服務方案評估時，若由方案執行單位自行進行評估者為「內部評估」（internal evaluation），若由機構以外的專家來進行評估者為「外部評估」（external evaluation）。下 列對於兩種評估方式的優缺點分析，何者正確？', '["內部評估具有「易於維持評估工作的客觀性」的優點", "「較易獲得主事者和員工的信任，進而讓其能承認問題和分享秘密」，是外部評估的優點", "內部評估的缺點之一是方案執行單位可能對服務相關的知識和經驗不足，影響評估工作的 深度", "外部評估的缺點之一是機構外的專家意見較缺乏獨立自主的可靠性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05259', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在進行需求評估時，方案規劃者應嘗試不同的測量方法，因為每種方法均有其優點，亦存在 著限制。下列對於需求評估方法之優點、缺點描述，何者錯誤？', '["以現有研究資料進行需求評估，能節省時間與資源，但運用時需考慮人口差異性和操作性 定義的議題", "詢問和參考專業人員或專家的判斷和建議做為需求評估的基礎，有助於提升方案申請的可 信度，但需注意偏見的議題", "社會或社區調查是最強而有力的需求評估方法，然而卻有時間和精力耗用的議題", "相較於社會或社區調查，公聽會在時間與金錢的花費較少，且代表性也足夠，然而舉辦的 時間與地點選擇是主要挑戰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
